// ---- Dependency Injection with Hilt ----
// Dependencies in build.gradle.kts (app):
// implementation("com.google.dagger:hilt-android:2.48")
// kapt("com.google.dagger:hilt-compiler:2.48")
// implementation("androidx.hilt:hilt-navigation-compose:1.1.0")

// ---- Application class ----
@HiltAndroidApp
class MyApplication : Application()

// ---- Module ----
@Module
@InstallIn(SingletonComponent::class)
object AppModule {

    @Provides
    @Singleton
    fun provideDatabase(@ApplicationContext context: Context): AppDatabase {
        return Room.databaseBuilder(
            context,
            AppDatabase::class.java,
            "app_database"
        ).build()
    }

    @Provides
    fun providePlayerDao(database: AppDatabase): PlayerDao {
        return database.playerDao()
    }

    @Provides
    @Singleton
    fun provideRetrofit(): Retrofit {
        return Retrofit.Builder()
            .baseUrl("https://api.example.com/")
            .addConverterFactory(GsonConverterFactory.create())
            .build()
    }

    @Provides
    fun provideApiService(retrofit: Retrofit): ApiService {
        return retrofit.create(ApiService::class.java)
    }

    @Provides
    @Singleton
    fun provideLocalDataSource(dao: PlayerDao): LocalDataSource {
        return LocalDataSourceImpl(dao)
    }

    @Provides
    @Singleton
    fun provideRemoteDataSource(api: ApiService): RemoteDataSource {
        return RemoteDataSourceImpl(api)
    }

    @Provides
    @Singleton
    fun provideRepository(
        local: LocalDataSource,
        remote: RemoteDataSource
    ): PlayerRepository {
        return CachingPlayerRepository(remote, local)
    }

    // ---- Use case dependencies ----
    @Provides
    fun provideGetPlayersUseCase(repository: PlayerRepository): GetPlayersUseCase {
        return GetPlayersUseCase(repository)
    }

    @Provides
    fun provideGetPlayerUseCase(repository: PlayerRepository): GetPlayerUseCase {
        return GetPlayerUseCase(repository)
    }

    @Provides
    fun provideSavePlayerUseCase(repository: PlayerRepository): SavePlayerUseCase {
        return SavePlayerUseCase(repository)
    }

    @Provides
    fun provideDeletePlayerUseCase(repository: PlayerRepository): DeletePlayerUseCase {
        return DeletePlayerUseCase(repository)
    }

    @Provides
    fun provideLevelUpUseCase(repository: PlayerRepository): LevelUpPlayerUseCase {
        return LevelUpPlayerUseCase(repository)
    }
}

// ---- Hilt ViewModel ----
@HiltViewModel
class PlayerViewModel @Inject constructor(
    private val getPlayers: GetPlayersUseCase,
    private val getPlayer: GetPlayerUseCase,
    private val savePlayer: SavePlayerUseCase,
    private val deletePlayer: DeletePlayerUseCase,
    private val levelUpPlayer: LevelUpPlayerUseCase
) : ViewModel() {
    data class UiState(
        val players: List<Player> = emptyList(),
        val selectedPlayer: Player? = null,
        val isLoading: Boolean = false,
        val error: String? = null
    )

    private val _uiState = MutableStateFlow(UiState())
    val uiState: StateFlow<UiState> = _uiState.asStateFlow()

    fun loadPlayers() {
        viewModelScope.launch {
            _uiState.update { it.copy(isLoading = true, error = null) }
            try {
                _uiState.update {
                    it.copy(
                        players = getPlayers(),
                        isLoading = false
                    )
                }
            } catch (e: Exception) {
                _uiState.update {
                    it.copy(error = e.message, isLoading = false)
                }
            }
        }
    }

    fun selectPlayer(id: Int) {
        viewModelScope.launch {
            _uiState.update { it.copy(isLoading = true) }
            try {
                val player = getPlayer(id)
                _uiState.update {
                    it.copy(selectedPlayer = player, isLoading = false)
                }
            } catch (e: Exception) {
                _uiState.update {
                    it.copy(error = e.message, isLoading = false)
                }
            }
        }
    }

    fun savePlayer(name: String, health: Int, attack: Int, defense: Int, level: Int) {
        viewModelScope.launch {
            _uiState.update { it.copy(isLoading = true) }
            try {
                val player = Player(0, name, health, attack, defense, level)
                savePlayer(player)
                loadPlayers()
            } catch (e: Exception) {
                _uiState.update {
                    it.copy(error = e.message, isLoading = false)
                }
            }
        }
    }

    fun deletePlayer(id: Int) {
        viewModelScope.launch {
            _uiState.update { it.copy(isLoading = true) }
            try {
                deletePlayer(id)
                _uiState.update { it.copy(selectedPlayer = null) }
                loadPlayers()
            } catch (e: Exception) {
                _uiState.update {
                    it.copy(error = e.message, isLoading = false)
                }
            }
        }
    }

    fun levelUp(id: Int) {
        viewModelScope.launch {
            _uiState.update { it.copy(isLoading = true) }
            try {
                val player = levelUpPlayer(id)
                _uiState.update {
                    it.copy(selectedPlayer = player, isLoading = false)
                }
                loadPlayers()
            } catch (e: Exception) {
                _uiState.update {
                    it.copy(error = e.message, isLoading = false)
                }
            }
        }
    }

    fun clearError() {
        _uiState.update { it.copy(error = null) }
    }
}

// ---- Hilt Compose Screen ----
@Composable
fun HiltScreen(
    viewModel: PlayerViewModel = hiltViewModel()
) {
    val uiState by viewModel.uiState.collectAsState()

    var name by remember { mutableStateOf("") }
    var health by remember { mutableStateOf("") }
    var attack by remember { mutableStateOf("") }
    var defense by remember { mutableStateOf("") }
    var level by remember { mutableStateOf("") }

    Scaffold(
        topBar = { TopAppBar { Text("Hilt DI Example") } }
    ) { paddingValues ->
        Column(
            modifier = Modifier
                .fillMaxSize()
                .padding(paddingValues)
                .padding(16.dp),
            verticalArrangement = Arrangement.spacedBy(8.dp)
        ) {
            if (uiState.isLoading) {
                Box(modifier = Modifier.fillMaxWidth().height(50.dp), contentAlignment = Alignment.Center) {
                    CircularProgressIndicator()
                }
            }

            if (uiState.error != null) {
                Card(
                    modifier = Modifier.fillMaxWidth(),
                    colors = CardDefaults.cardColors(
                        containerColor = MaterialTheme.colorScheme.errorContainer
                    )
                ) {
                    Column(modifier = Modifier.padding(16.dp)) {
                        Text(uiState.error ?: "", color = MaterialTheme.colorScheme.onErrorContainer)
                        Button(onClick = { viewModel.clearError() }) { Text("Dismiss") }
                    }
                }
            }

            if (uiState.selectedPlayer != null) {
                Card(
                    modifier = Modifier.fillMaxWidth(),
                    elevation = CardDefaults.cardElevation(4.dp)
                ) {
                    Column(modifier = Modifier.padding(16.dp)) {
                        Text("Selected:", style = MaterialTheme.typography.titleMedium)
                        Text(uiState.selectedPlayer?.name ?: "")
                        Text("HP: ${uiState.selectedPlayer?.health}")
                        Text("ATK: ${uiState.selectedPlayer?.attack}")
                        Text("DEF: ${uiState.selectedPlayer?.defense}")
                        Text("Lv: ${uiState.selectedPlayer?.level}")
                        Button(onClick = {
                            uiState.selectedPlayer?.let {
                                viewModel.levelUp(it.id)
                            }
                        }) {
                            Text("Level Up")
                        }
                        Button(
                            onClick = {
                                uiState.selectedPlayer?.let {
                                    viewModel.deletePlayer(it.id)
                                }
                            },
                            colors = ButtonDefaults.buttonColors(
                                containerColor = MaterialTheme.colorScheme.error
                            )
                        ) {
                            Text("Delete")
                        }
                    }
                }
            }

            // ---- Add player form ----
            Text("Add Player", style = MaterialTheme.typography.titleMedium)
            Row(modifier = Modifier.fillMaxWidth(), horizontalArrangement = Arrangement.spacedBy(8.dp)) {
                OutlinedTextField(
                    value = name,
                    onValueChange = { name = it },
                    label = { Text("Name") },
                    modifier = Modifier.weight(2f)
                )
                OutlinedTextField(
                    value = health,
                    onValueChange = { health = it },
                    label = { Text("HP") },
                    modifier = Modifier.weight(1f)
                )
                OutlinedTextField(
                    value = attack,
                    onValueChange = { attack = it },
                    label = { Text("ATK") },
                    modifier = Modifier.weight(1f)
                )
            }
            Row(modifier = Modifier.fillMaxWidth(), horizontalArrangement = Arrangement.spacedBy(8.dp)) {
                OutlinedTextField(
                    value = defense,
                    onValueChange = { defense = it },
                    label = { Text("DEF") },
                    modifier = Modifier.weight(1f)
                )
                OutlinedTextField(
                    value = level,
                    onValueChange = { level = it },
                    label = { Text("Lv") },
                    modifier = Modifier.weight(1f)
                )
                Button(
                    onClick = {
                        val h = health.toIntOrNull() ?: 100
                        val a = attack.toIntOrNull() ?: 10
                        val d = defense.toIntOrNull() ?: 5
                        val l = level.toIntOrNull() ?: 1
                        if (name.isNotBlank()) {
                            viewModel.savePlayer(name, h, a, d, l)
                            name = ""; health = ""; attack = ""; defense = ""; level = ""
                        }
                    },
                    modifier = Modifier.weight(1f)
                ) { Text("Add") }
            }

            // ---- Players list ----
            LazyColumn(verticalArrangement = Arrangement.spacedBy(4.dp)) {
                items(uiState.players) { player ->
                    Card(
                        modifier = Modifier
                            .fillMaxWidth()
                            .clickable { viewModel.selectPlayer(player.id) },
                        elevation = CardDefaults.cardElevation(2.dp)
                    ) {
                        Row(
                            modifier = Modifier.fillMaxWidth().padding(8.dp),
                            horizontalArrangement = Arrangement.SpaceBetween,
                            verticalAlignment = Alignment.CenterVertically
                        ) {
                            Text(player.name, style = MaterialTheme.typography.titleMedium)
                            Text("Lv.${player.level}", style = MaterialTheme.typography.bodyMedium)
                        }
                    }
                }
            }

            Button(
                onClick = { viewModel.loadPlayers() },
                modifier = Modifier.fillMaxWidth()
            ) { Text("Refresh") }
        }
    }
}

