// ---- Application ----
package com.example.hilt

import android.app.Application
import dagger.hilt.android.HiltAndroidApp

@HiltAndroidApp
class MyApplication : Application()

// ---- Module ----
package com.example.hilt.di

import dagger.Module
import dagger.Provides
import dagger.hilt.InstallIn
import dagger.hilt.components.SingletonComponent
import javax.inject.Singleton

@Module
@InstallIn(SingletonComponent::class)
object AppModule {
    @Provides
    @Singleton
    fun provideRepository(): Repository {
        return RepositoryImpl()
    }

    @Provides
    fun provideGetMessageUseCase(repository: Repository): GetMessageUseCase {
        return GetMessageUseCase(repository)
    }
}

// ---- Domain ----
interface Repository {
    suspend fun getMessage(): String
}

class RepositoryImpl : Repository {
    override suspend fun getMessage(): String {
        return "Hello from Hilt!"
    }
}

class GetMessageUseCase(
    private val repository: Repository
) {
    suspend operator fun invoke(): String {
        return repository.getMessage()
    }
}

// ---- ViewModel ----
package com.example.hilt.presentation

import androidx.compose.runtime.*
import androidx.compose.foundation.layout.*
import androidx.compose.material3.*
import androidx.compose.ui.Alignment
import androidx.compose.ui.Modifier
import androidx.compose.ui.unit.dp
import androidx.hilt.navigation.compose.hiltViewModel
import androidx.lifecycle.ViewModel
import androidx.lifecycle.viewModelScope
import dagger.hilt.android.lifecycle.HiltViewModel
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.flow.asStateFlow
import kotlinx.coroutines.flow.update
import kotlinx.coroutines.launch
import javax.inject.Inject

@HiltViewModel
class MyViewModel @Inject constructor(
    private val getMessage: GetMessageUseCase
) : ViewModel() {
    data class UiState(
        val message: String = "",
        val isLoading: Boolean = false,
        val error: String? = null
    )

    private val _uiState = MutableStateFlow(UiState())
    val uiState: StateFlow<UiState> = _uiState.asStateFlow()

    fun loadMessage() {
        viewModelScope.launch {
            _uiState.update { it.copy(isLoading = true, error = null) }
            try {
                val msg = getMessage()
                _uiState.update { it.copy(message = msg, isLoading = false) }
            } catch (e: Exception) {
                _uiState.update { it.copy(error = e.message, isLoading = false) }
            }
        }
    }
}

// ---- UI ----
@Composable
fun HiltDemoScreen(
    viewModel: MyViewModel = hiltViewModel()
) {
    val uiState by viewModel.uiState.collectAsState()

    Column(
        modifier = Modifier.fillMaxSize().padding(16.dp),
        horizontalAlignment = Alignment.CenterHorizontally,
        verticalArrangement = Arrangement.spacedBy(16.dp)
    ) {
        if (uiState.isLoading) {
            CircularProgressIndicator()
        }

        if (uiState.error != null) {
            Text(uiState.error ?: "", color = MaterialTheme.colorScheme.error)
        }

        Text(
            text = uiState.message,
            style = MaterialTheme.typography.headlineMedium
        )

        Button(onClick = { viewModel.loadMessage() }) {
            Text("Load Message")
        }
    }
}
